properties.formula:
var bool untouched = [Description]=[Most Recent Chat Log Note];
var bool complete = not(IsNull([Completed Timestamp]));
var text incomplete = If([Official Due Date]>=Today(),"On Track","Past Due");
var text SLA = If([Official Due Date]>=ToDate([Completed Timestamp]),"In SLA","Out of SLA");

If($untouched,"Untouched",$complete,"Complete - "&$SLA,"Open - "&$incomplete)

If (
    // Stop the timer once the Ticket is completed
    not IsNull([Completed Timestamp]),
    [Completed Timestamp] - [Date/Time Created],

    // Default to running timer
    Now() - [Date/Time Created]
)
